using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_32b4f996685c4e3c98280046e15b5959.Client;

namespace sv_32b4f996685c4e3c98280046e15b5959;

/// <summary>
/// Server-side provider that returns hardcoded claims and persists them
/// into PersistentComponentState so the WebAssembly runtime can pick them up.
/// </summary>
public sealed class PersistingAuthenticationStateProvider
    : AuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentState;
    private readonly HardcodedAuthenticationStateProvider _inner = new();
    private readonly PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authTask;

    public PersistingAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        _persistentState = persistentState;
        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
    {
        _authTask ??= _inner.GetAuthenticationStateAsync();
        return _authTask;
    }

    private async Task OnPersistingAsync()
    {
        var state = await GetAuthenticationStateAsync();
        var principal = state.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            _persistentState.PersistAsJson(nameof(UserInfo), UserInfo.FromClaimsPrincipal(principal));
        }
    }

    public void Dispose() => _subscription.Dispose();
}

using System.Security.Claims;

namespace sv_32b4f996685c4e3c98280046e15b5959.Client;

/// <summary>
/// Lightweight DTO serialized into PersistentComponentState on the server
/// and deserialized on the WebAssembly client.
/// </summary>
public sealed class UserInfo
{
    public required string Name { get; set; }
    public required string[] Roles { get; set; }
    public required UserClaim[] Claims { get; set; }

    public static UserInfo FromClaimsPrincipal(ClaimsPrincipal principal) => new()
    {
        Name = principal.Identity?.Name ?? string.Empty,
        Roles = principal.Claims
            .Where(c => c.Type == ClaimTypes.Role)
            .Select(c => c.Value)
            .ToArray(),
        Claims = principal.Claims
            .Select(c => new UserClaim { Type = c.Type, Value = c.Value })
            .ToArray(),
    };

    public ClaimsPrincipal ToClaimsPrincipal()
    {
        var claims = Claims.Select(c => new Claim(c.Type, c.Value));
        var identity = new ClaimsIdentity(claims, authenticationType: "Persisted");
        return new ClaimsPrincipal(identity);
    }
}

public sealed class UserClaim
{
    public required string Type { get; set; }
    public required string Value { get; set; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_32b4f996685c4e3c98280046e15b5959.Client;

/// <summary>
/// Client-side (WebAssembly) provider that reads the persisted auth state
/// from PersistentComponentState, ensuring auth survives the WASM handoff.
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authState;

    public PersistentAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (persistentState.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo)
            && userInfo is not null)
        {
            _authState = Task.FromResult(new AuthenticationState(userInfo.ToClaimsPrincipal()));
        }
        else
        {
            _authState = _unauthenticated;
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authState;
}

